import { useState, useEffect } from 'react'
import { useParams } from 'react-router-dom'
import StarWarsAPI from '../services/StarWarsAPI'
import Card from 'react-bootstrap/Card'
import CardBody from 'react-bootstrap/Card'
import Button from 'react-bootstrap/Button'
import { Link } from 'react-router-dom'
import Table from 'react-bootstrap/Table'
import ListGroup from 'react-bootstrap/ListGroup'
import getIdFromUrl from '../services/StarWarsAPI'

const Film = () => {
	const [film, setFilm] = useState()
	const { id } = useParams()

	const getFilm = async (id) => {
		const data = await StarWarsAPI.getFilm(id)
		setFilm(data)
	}
	const getID = () => {
		const arrCharacters = film.characters;
		const arrID = [];
		for(let i = 0; i < arrCharacters.length; i++){
			let CharacterID = getIdFromUrl(arrCharacters[i])
			arrID.push(CharacterID);
		}
		return arrID
	}

    useEffect(() => {
		getFilm(id)
	}, [id])

	if (!film) {
		return <p>Loading...</p>
	}

    return (
		<>
		{film && (
				   <Card className="film">
					   {/* <Card.Img variant="top" src=""/> */}
					   <CardBody className="film-body">
					   <Card.Title className="film-title">{film.title}</Card.Title>
					   <Card.Subtitle className="film-subtitle">Attributes</Card.Subtitle>
					   <Table>
					   <tbody>
    						<tr>
      							<td className="attribute">Episode</td>
      							<td>{film.episode_id}</td>
    						</tr>
    						<tr>
      							<td className="attribute">Director</td>
      							<td>{film.director}</td>
    						</tr>
							<tr>
      							<td className="attribute">Producer</td>
      							<td>{film.producer}</td>
    						</tr>
							<tr>
      							<td className="attribute">Released</td>
      							<td>{film.release_date}</td>
    						</tr>
							<tr>
      							<td className="film-links">Links</td>
    						</tr>
							<tr>
      							<td>Characters</td>
								  <td>
								  <ListGroup>
								  {arrID.map((film, index) =>

								<ListGroup.Item key={++index}><Link to={`/people/${++index}`} className="character-link">Film {index}  {`>>`}</Link></ListGroup.Item>

								 )}

								 </ListGroup>
								 </td>
    						</tr>
						</tbody>
					   </Table>
					   <Button variant="primary" as={Link} to={`/films`} className="film-goback">{`<<`} Go back</Button>
					   </CardBody>
				   </Card>


	   )} 

	   {!film && (
		   <p className="status">No film!</p>
	   )}
	   </>
	)
}

export default Film
